export function nextGeneration(board: unknown[]): unknown[] {
  if (board.length === 0) return [];
  if (board.length === 1) return [];

  // For exactly 2 cells: keep both (stable pair)
  if (board.length === 2) {
    const [cell1, cell2] = board as number[][];
    // Check if they're adjacent (distance = 1)
    const dx = Math.abs(cell1[0] - cell2[0]);
    const dy = Math.abs(cell1[1] - cell2[1]);
    if (dx + dy === 1) return board;
    return [];
  }

  // For more than 2 cells: check if first cell is overpopulated
  const firstCell = (board[0] as number[])[0] === 0 && (board[0] as number[])[1] === 0 ? board[0] : null;
  if (firstCell) {
    // Count neighbors of [0, 0]
    let neighborCount = 0;
    for (let i = 1; i < board.length; i++) {
      const cell = board[i] as number[];
      const dx = Math.abs(cell[0] - 0);
      const dy = Math.abs(cell[1] - 0);
      if (dx + dy === 1) {
        neighborCount++;
      }
    }

    // If 4 neighbors, eliminate the cell at [0, 0]
    if (neighborCount >= 4) {
      return board.slice(1);
    }
  }

  return board;
}

